// Strategies for generating test inputs
fn hostcall_type_strategy() -> impl Strategy<Value = String> {
    prop_oneof\![
        Just("tool".to_string()),
        Just("exec".to_string()),
        Just("http".to_string()),
        Just("session".to_string()),
        Just("ui".to_string()),
        Just("events".to_string()),
        "[a-z]{1,10}".prop_map(String::from),  // Random invalid types
    ]
